mapper.select:
SELECT COUNT(*)
  FROM user_nickname_profile
 WHERE nickname = #{nickname}

   AND id != #{excludeId}

mapper.update:
UPDATE user_nickname_profile
   SET nickname = #{nickname},
       avatar_file_id = #{avatarFileId},
       bio = #{bio}
 WHERE id = #{id}
   AND user_id = #{userId}

UPDATE user_nickname_profile
   SET status = 'HIDDEN'
 WHERE id = #{id}
   AND user_id = #{userId}
   AND status = 'ACTIVE'

UPDATE user_nickname_profile
   SET is_default = 1
 WHERE id = #{id}
   AND user_id = #{userId}
   AND status = 'ACTIVE'

