SELECT conversation_id, user_id, nickname_profile_id, anonymous, updated_at
  FROM conversation_member_profile
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}

SELECT COUNT(*)
  FROM collaboration_conversation_member
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}
   AND status = 'ACTIVE'
